import React from 'react';
import './App.css';
import { Link, useNavigate } from 'react-router-dom'; 

const Modal = ({ isOpen, onClose }) => { 
    if (!isOpen) return null;  // isOpen이 false일 때 모달을 렌더링하지 않음

    const navigate = useNavigate();  // useNavigate 훅 호출

    function handleClick() {
        // navigate로 페이지 이동
        navigate('/diarypage');
    }

    return (
        <div className='modal'>
            <ul className='modal_1'>
                <li>
                    {/* 클릭 시 navigate로 /diarypage로 이동 */}
                    <span onClick={handleClick}>잘자요</span> 
                </li>
                <li>
                    <Link to='/'>애칭 설정</Link> {/* Link를 사용하여 / 경로로 이동 */}
                </li>
                <li>
                    <Link to='/'>Diray List</Link>
                </li>
            </ul>
            <ul className='modal_2'>
                <li></li>
            </ul> 
        </div>
    );
}

export default Modal;

